const fs = require('fs');
const path = '/root/obm-ci-suite/data/leads_linkedin_ci.jsonl';
const leads = fs.readFileSync(path, 'utf8').split('\n').filter(l => l.trim()).map(l => JSON.parse(l));
return leads.map(l => ({json: {phone: l.phone_whatsapp, message: `Bonjour ${l.first_name}, nous distribuons ${l.interest[0]} adapté à vos besoins. Budget: ${l.budget}. Intéressé ?`}}));
